     1	export type OrderState =
     2	  | "PENDING"
     3	  | "CONFIRMED"
     4	  | "SHIPPED"
     5	  | "DELIVERED"
     6	  | "CANCELLED";
     7	
     8	// Maps each state to the set of states it may legally transition into.
     9	const VALID_TRANSITIONS: Record<OrderState, ReadonlySet<OrderState>> = {
    10	  PENDING:   new Set(["CONFIRMED", "CANCELLED"]),
    11	  CONFIRMED: new Set(["SHIPPED",   "CANCELLED"]),
    12	  SHIPPED:   new Set(["DELIVERED"]),
    13	  DELIVERED: new Set(), // terminal state
    14	  CANCELLED: new Set(), // terminal state
    15	};
    16	
    17	export class InvalidTransitionError extends Error {
    18	  readonly code = "INVALID_TRANSITION";
    19	
    20	  constructor(from: OrderState, to: OrderState) {
    21	    super(`Cannot transition from ${from} to ${to}`);
    22	    this.name = "InvalidTransitionError";
    23	    // Restore prototype chain (required when extending built-ins in TS/ES5 targets)
    24	    Object.setPrototypeOf(this, new.target.prototype);
    25	  }
    26	}
    27	
    28	export class OrderStateMachine {
    29	  /**
    30	   * Attempt to move an order from `currentState` to `targetState`.
    31	   *
    32	   * @returns `targetState` when the transition is valid.
    33	   * @throws  `InvalidTransitionError` (with `.code === "INVALID_TRANSITION"`) when invalid.
    34	   */
    35	  transition(currentState: OrderState, targetState: OrderState): OrderState {
    36	    if (!VALID_TRANSITIONS[currentState].has(targetState)) {
    37	      throw new InvalidTransitionError(currentState, targetState);
    38	    }
    39	    return targetState;
    40	  }
    41	}
