     1	import { OrderStateMachine, InvalidTransitionError, OrderState } from "./OrderStateMachine";
     2	
     3	describe("OrderStateMachine", () => {
     4	  let machine: OrderStateMachine;
     5	
     6	  beforeEach(() => {
     7	    machine = new OrderStateMachine();
     8	  });
     9	
    10	  // -----------------------------------------------------------------------
    11	  // AC1 — Valid transitions
    12	  // -----------------------------------------------------------------------
    13	  describe("valid transitions (AC1)", () => {
    14	    const cases: Array<[OrderState, OrderState]> = [
    15	      ["PENDING",   "CONFIRMED"],
    16	      ["CONFIRMED", "SHIPPED"],
    17	      ["SHIPPED",   "DELIVERED"],
    18	      ["CONFIRMED", "CANCELLED"],
    19	      ["PENDING",   "CANCELLED"],
    20	    ];
    21	
    22	    test.each(cases)(
    23	      "%s -> %s succeeds and returns target state",
    24	      (from, to) => {
    25	        expect(machine.transition(from, to)).toBe(to);
    26	      },
    27	    );
    28	  });
    29	
    30	  // -----------------------------------------------------------------------
    31	  // AC2 — Invalid transitions throw INVALID_TRANSITION
    32	  // -----------------------------------------------------------------------
    33	  describe("invalid transitions throw INVALID_TRANSITION (AC2)", () => {
    34	    const invalidCases: Array<[OrderState, OrderState]> = [
    35	      ["DELIVERED", "SHIPPED"],    // AC2 example
    36	      ["SHIPPED",   "PENDING"],    // AC2 example / AC6
    37	      ["DELIVERED", "PENDING"],
    38	      ["DELIVERED", "CONFIRMED"],
    39	      ["DELIVERED", "CANCELLED"],
    40	      ["DELIVERED", "DELIVERED"],
    41	      ["SHIPPED",   "CONFIRMED"],
    42	      ["SHIPPED",   "CANCELLED"],
    43	      ["PENDING",   "SHIPPED"],
    44	      ["PENDING",   "DELIVERED"],
    45	    ];
    46	
    47	    test.each(invalidCases)(
    48	      "%s -> %s throws with code INVALID_TRANSITION",
    49	      (from, to) => {
    50	        expect(() => machine.transition(from, to)).toThrow();
    51	        try {
    52	          machine.transition(from, to);
    53	        } catch (err) {
    54	          expect((err as InvalidTransitionError).code).toBe("INVALID_TRANSITION");
    55	        }
    56	      },
    57	    );
    58	  });
    59	
    60	  // -----------------------------------------------------------------------
    61	  // AC3 — CANCELLED is a terminal state
    62	  // -----------------------------------------------------------------------
    63	  describe("CANCELLED is a terminal state (AC3)", () => {
    64	    const targets: OrderState[] = ["PENDING", "CONFIRMED", "SHIPPED", "DELIVERED", "CANCELLED"];
    65	
    66	    test.each(targets)("CANCELLED -> %s throws INVALID_TRANSITION", (to) => {
    67	      expect(() => machine.transition("CANCELLED", to)).toThrow();
    68	      try {
    69	        machine.transition("CANCELLED", to);
    70	      } catch (err) {
    71	        expect((err as InvalidTransitionError).code).toBe("INVALID_TRANSITION");
    72	      }
    73	    });
    74	  });
    75	
    76	  // -----------------------------------------------------------------------
    77	  // AC4 — DELIVERED is a terminal state
    78	  // -----------------------------------------------------------------------
    79	  describe("DELIVERED is a terminal state (AC4)", () => {
    80	    const targets: OrderState[] = ["PENDING", "CONFIRMED", "SHIPPED", "DELIVERED", "CANCELLED"];
    81	
    82	    test.each(targets)("DELIVERED -> %s throws INVALID_TRANSITION", (to) => {
    83	      expect(() => machine.transition("DELIVERED", to)).toThrow();
    84	      try {
    85	        machine.transition("DELIVERED", to);
    86	      } catch (err) {
    87	        expect((err as InvalidTransitionError).code).toBe("INVALID_TRANSITION");
    88	      }
    89	    });
    90	  });
    91	
    92	  // -----------------------------------------------------------------------
    93	  // AC5 — PENDING -> CONFIRMED happy path
    94	  // -----------------------------------------------------------------------
    95	  it("AC5: PENDING -> CONFIRMED returns CONFIRMED", () => {
    96	    expect(machine.transition("PENDING", "CONFIRMED")).toBe("CONFIRMED");
    97	  });
    98	
    99	  // -----------------------------------------------------------------------
   100	  // AC6 — SHIPPED -> PENDING throws
   101	  // -----------------------------------------------------------------------
   102	  it("AC6: SHIPPED -> PENDING throws INVALID_TRANSITION", () => {
   103	    expect(() => machine.transition("SHIPPED", "PENDING")).toThrow();
   104	    try {
   105	      machine.transition("SHIPPED", "PENDING");
   106	    } catch (err) {
   107	      expect((err as InvalidTransitionError).code).toBe("INVALID_TRANSITION");
   108	    }
   109	  });
   110	
   111	  // -----------------------------------------------------------------------
   112	  // Error shape — message and name are informative
   113	  // -----------------------------------------------------------------------
   114	  it("error message includes both states", () => {
   115	    try {
   116	      machine.transition("DELIVERED", "SHIPPED");
   117	      fail("expected throw");
   118	    } catch (err) {
   119	      const e = err as InvalidTransitionError;
   120	      expect(e.message).toContain("DELIVERED");
   121	      expect(e.message).toContain("SHIPPED");
   122	      expect(e.name).toBe("InvalidTransitionError");
   123	    }
   124	  });
   125	
   126	  it("error is instanceof Error", () => {
   127	    try {
   128	      machine.transition("CANCELLED", "PENDING");
   129	    } catch (err) {
   130	      expect(err).toBeInstanceOf(Error);
   131	      expect(err).toBeInstanceOf(InvalidTransitionError);
   132	    }
   133	  });
   134	});

